import{_ as a,o as e,c as s,ag as n}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"Alias Permission | Dotfiles (ID)","titleTemplate":":title","description":"Jelajahi alias Permission untuk Dotfiles Kompatibel dengan macOS, Linux, dan WSL melalui Dotfiles.","frontmatter":{"title":"Alias Permission | Dotfiles","description":"Jelajahi alias Permission untuk Dotfiles Kompatibel dengan macOS, Linux, dan WSL melalui Dotfiles.","lang":"id-ID","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias Permission preview","canonical":"/id/aliases/permission/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias Permission","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias Permission - Dotfiles (ID)","permalink":"/id/aliases/permission/"},"headers":[],"relativePath":"id/aliases/permission/index.md","filePath":"id/aliases/permission/index.md","lastUpdated":1773010926000}'),l={name:"id/aliases/permission/index.md"};function t(o,i,d,r,u,c){return e(),s("div",null,[...i[0]||(i[0]=[n('<h1 id="alias-permission" tabindex="-1">Alias Permission <a class="header-anchor" href="#alias-permission" aria-label="Permalink to &quot;Alias Permission&quot;">​</a></h1><p>Kelola alias permission. Bagian dari konfigurasi <strong>Universal Dotfiles</strong>.</p><h2 id="ikhtisar" tabindex="-1">Ikhtisar <a class="header-anchor" href="#ikhtisar" aria-label="Permalink to &quot;Ikhtisar&quot;">​</a></h2><p>Alias ini didefinisikan di <code>permission.aliases.sh</code> dan dimuat secara otomatis oleh <code>chezmoi</code>.</p><h2 id="alias" tabindex="-1">Alias <a class="header-anchor" href="#alias" aria-label="Permalink to &quot;Alias&quot;">​</a></h2><p>Kode ini menyediakan set alias untuk izin file.</p><ul><li><code>000</code> Tidak ada izin baca, tulis, atau eksekusi untuk pengguna, grup, atau lainnya.</li><li><code>400</code> Tidak ada izin baca atau tulis, tapi izinkan eksekusi hanya untuk pengguna.</li><li><code>444</code> Tidak ada izin tulis atau eksekusi, tapi izinkan baca untuk semua.</li><li><code>600</code> Atur izin baca dan tulis hanya untuk pengguna.</li><li><code>644</code> Atur izin baca untuk semua, tapi izinkan tulis hanya untuk pengguna.</li><li><code>666</code> Atur izin baca dan tulis untuk semua.</li><li><code>755</code> Atur izin baca, tulis, dan eksekusi untuk pengguna, tapi hanya baca dan eksekusi untuk grup dan lainnya.</li><li><code>764</code> Atur izin baca dan tulis untuk pengguna dan grup, tapi hanya baca untuk lainnya.</li><li><code>777</code> Atur izin baca, tulis, dan eksekusi untuk semua.</li><li><code>chgrp</code> Ubah kepemilikan grup file atau direktori.</li><li><code>chgrpr</code> Ubah kepemilikan grup file atau direktori secara rekursif.</li><li><code>chmod</code> Ubah bit mode file.</li><li><code>chmodr</code> Ubah bit mode file secara rekursif.</li><li><code>chmox</code> Jadikan file dapat dieksekusi.</li><li><code>chown</code> Ubah pemilik dan grup file.</li><li><code>chownr</code> Ubah pemilik dan grup file secara rekursif.</li></ul>',7)])])}const k=a(l,[["render",t]]);export{m as __pageData,k as default};
